import{_ as e,o as r,c as o,a2 as t}from"./chunks/framework.DIMps2S2.js";const b=JSON.parse('{"title":"下载 App","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"getting-started/download-app.md","filePath":"zh-CN/getting-started/download-app.md"}'),p={name:"getting-started/download-app.md"};function l(i,a,n,d,s,h){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="下载-app" tabindex="-1">下载 App <a class="header-anchor" href="#下载-app" aria-label="Permalink to &quot;下载 App&quot;">​</a></h1><p>长桥 App 支持安卓、iOS、Mac 及 Windows 四个平台，本页提供各平台下载链接与安装说明。</p><blockquote><p>以下下载链接的版本不一定是最新版本，安装后可在 App 内自行检查更新。</p></blockquote><h2 id="安卓" tabindex="-1">安卓 <a class="header-anchor" href="#安卓" aria-label="Permalink to &quot;安卓&quot;">​</a></h2><p><a href="https://static.lbkrs.com/app/longbridge-online-release.apk" target="_blank" rel="noreferrer">下载链接</a></p><h2 id="苹果-ios" tabindex="-1">苹果（iOS） <a class="header-anchor" href="#苹果-ios" aria-label="Permalink to &quot;苹果（iOS）&quot;">​</a></h2><p>长桥 iOS App 已在中国大陆 App Store 下架，中国大陆地区用户无法通过中国大陆 Apple ID 下载。海外其他地区用户可使用当地 Apple ID 在 App Store 正常搜索并下载。</p><h3 id="更新已安装的-app" tabindex="-1">更新已安装的 App <a class="header-anchor" href="#更新已安装的-app" aria-label="Permalink to &quot;更新已安装的 App&quot;">​</a></h3><p>打开【设置】→【App Store】→ 开启【App 更新】，即可自动更新。也可在 App Store 右上角头像 →【账户】页面下拉刷新后，进入【App】或【已购项目】手动更新。</p><h3 id="常见问题-在【已购项目】中找不到长桥" tabindex="-1">常见问题：在【已购项目】中找不到长桥 <a class="header-anchor" href="#常见问题-在【已购项目】中找不到长桥" aria-label="Permalink to &quot;常见问题：在【已购项目】中找不到长桥&quot;">​</a></h3><ol><li><strong>App 被隐藏</strong>：App Store → 右上角头像 → 账户 → 顶部账户名 →【账户设置】→【隐藏的已购项目】，找到&quot;长桥&quot;后点击【解除隐藏】；</li><li><strong>Apple ID 不匹配</strong>：当前登录的 Apple ID 不是当初下载时使用的账号，切换回原 Apple ID 后重试。</li></ol><h2 id="mac" tabindex="-1">Mac <a class="header-anchor" href="#mac" aria-label="Permalink to &quot;Mac&quot;">​</a></h2><p><a href="https://download.wbrks.com/longbridge-desktop/prod/longbridge-pro-2.33.3-mac-x64.dmg" target="_blank" rel="noreferrer">x64 版本</a><br><a href="https://download.wbrks.com/longbridge-desktop/prod/longbridge-pro-2.33.3-mac-arm64.dmg" target="_blank" rel="noreferrer">M 芯片版本</a></p><h2 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h2><p><a href="https://download.wbrks.com/longbridge-desktop/prod/longbridge-pro-2.33.3-win-ia32.exe" target="_blank" rel="noreferrer">32 位系统</a><br><a href="https://download.wbrks.com/longbridge-desktop/prod/longbridge-pro-2.33.3-win-x64.exe" target="_blank" rel="noreferrer">64 位系统</a></p><h2 id="中国大陆存量用户说明" tabindex="-1">中国大陆存量用户说明 <a class="header-anchor" href="#中国大陆存量用户说明" aria-label="Permalink to &quot;中国大陆存量用户说明&quot;">​</a></h2><p>长桥已停止接受中国大陆境内用户通过存量证明方式开户。中国大陆境内已有账户的存量用户可继续正常使用长桥客户端进行投资交易，相关服务不受影响。</p><p>访问长桥官网时可能遇到卡顿或受限，建议直接通过 App 使用。如需客服支持，可通过 App 内【我的】-【帮助与客服】联系，或致电 +852 3851 1777。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/getting-started/login-and-register">登录注册</a> — 账户登录与注册流程</li><li><a href="/wiki/getting-started/profile">我的</a> — App 我的页面功能说明</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/getting-started">新手入门</a></li></ul>',22)])])}const g=e(p,[["render",l]]);export{b as __pageData,g as default};
